// CONF-01: Assemble per-client config for Core Workflow
// Non-sensitive values hardcoded here (safe to commit)
// Sensitive values read from env vars with MARTIN_ prefix
const lead = $input.first().json;

const clientConfig = {
  client_slug: 'cabinet-martin',
  business_name: 'Cabinet Martin Avocats',
  service_type: 'avocat',
  city: 'Lyon',
  owner_phone: '+33600000001',
  brevo_sender_email: 'no-reply@cabinet-martin.fr',
  callback_promise_minutes: 60,
  follow_up_delay_minutes: 120,
  follow_up_enabled: true,
  // Sensitive: read from n8n env vars — never hardcoded
  twilio_account_sid: $env.MARTIN_TWILIO_ACCOUNT_SID,
  twilio_auth_token: $env.MARTIN_TWILIO_AUTH_TOKEN,
  twilio_sender_id: $env.MARTIN_TWILIO_SENDER_ID
};

// Merge lead payload with client config
return [{ json: { ...lead, client_config: clientConfig } }];
